mapper.select:
SELECT CASE WHEN COUNT(1) > 0 THEN 1 ELSE 0 END
FROM   USER_TRUSTED_IPS
WHERE  user_id         = #{userId}
  AND  ip_address_hash = #{ipAddressHash}
  AND  deleted_yn      = 'N'

mapper.update:
UPDATE USER_TRUSTED_IPS
SET    last_used_at = SYSTIMESTAMP
WHERE  trust_id = #{trustId}

UPDATE USER_TRUSTED_IPS
SET    nickname = #{nickname}
WHERE  trust_id   = #{trustId}
  AND  user_id    = #{userId}
  AND  deleted_yn = 'N'
